
$vuln: #ff6b9d;
$safe: #79c48a;
$warn: #e8a94f;
$danger: #e06868;
$info: #6fb9dc;
$serif: 'Noto Serif SC', 'Songti SC', 'STSong', serif;

// 移动端单列；宽屏两列并排（左：状态+植入，右：念头/习惯/仪容），压缩整体高度
.char-panel {
  display: flex;
  flex-direction: column;
  gap: 11px;
}
.col {
  display: flex;
  flex-direction: column;
  gap: 11px;
  min-width: 0;
}
@media (min-width: 560px) {
  .char-panel {
    display: grid;
    grid-template-columns: 1.02fr 0.98fr;
    align-items: start;
  }
}

// ━━━ hero ━━━
.hero {
  display: flex;
  flex-direction: column;
  gap: 10px;
  padding: 12px 13px;
  border: 1px solid var(--line);
  border-radius: 10px;
  background: linear-gradient(160deg, var(--panel), rgba(0, 0, 0, 0.25));
  backdrop-filter: blur(4px);
  box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.04);
}
.hero-top {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 10px;
}
.stage {
  display: flex;
  align-items: center;
  gap: 10px;
  min-width: 0;
}
.stage-no {
  flex: none;
  width: 40px;
  height: 40px;
  display: flex;
  align-items: center;
  justify-content: center;
  border-radius: 50%;
  border: 1.5px solid color-mix(in srgb, var(--acc) 65%, transparent);
  color: var(--acc);
  font-size: 19px;
  font-weight: 800;
  font-family: $serif;
  background: radial-gradient(circle, color-mix(in srgb, var(--acc) 12%, transparent), transparent 70%);
  text-shadow: 0 0 12px var(--glow);
  box-shadow: 0 0 14px color-mix(in srgb, var(--acc) 15%, transparent);
}
.stage-meta {
  display: flex;
  flex-direction: column;
  min-width: 0;

  .stage-title {
    font-family: $serif;
    font-size: 16px;
    font-weight: 700;
    color: var(--acc);
    letter-spacing: 3px;
    line-height: 1.3;
    text-shadow: 0 0 10px var(--glow);
  }
  small {
    font-size: 10.5px;
    color: color-mix(in srgb, var(--acc) 45%, #998);
    letter-spacing: 0.6px;
  }
}
.emotion {
  flex: none;
  font-size: 12px;
  color: #d5cabb;
  padding: 3px 12px;
  border-radius: 20px;
  border: 1px solid var(--line);
  background: rgba(0, 0, 0, 0.28);
  letter-spacing: 1px;

  &.vuln {
    color: $vuln;
    border-color: rgba(255, 107, 157, 0.5);
    font-weight: 700;
    animation: vuln-pulse 1.6s ease-in-out infinite;
  }
}
@keyframes vuln-pulse {
  0%,
  100% {
    box-shadow: 0 0 4px rgba(255, 107, 157, 0.25);
  }
  50% {
    box-shadow: 0 0 14px rgba(255, 107, 157, 0.6);
  }
}

// ━━━ 三维 ━━━
.bars {
  display: flex;
  flex-direction: column;
  gap: 7px;
}
.bar {
  display: flex;
  align-items: center;
  gap: 9px;
  font-size: 11.5px;
}
.bl {
  flex: none;
  width: 34px;
  color: color-mix(in srgb, var(--acc) 50%, #998);
  letter-spacing: 1px;
}
.track {
  flex: 1;
  height: 6px;
  border-radius: 3px;
  background: rgba(0, 0, 0, 0.5);
  overflow: hidden;
  box-shadow: inset 0 1px 3px rgba(0, 0, 0, 0.4);
}
.fill {
  display: block;
  height: 100%;
  border-radius: 3px;
  transition: width 0.5s cubic-bezier(0.4, 0, 0.2, 1);
  position: relative;

  &::after {
    content: '';
    position: absolute;
    inset: 0;
    background: linear-gradient(180deg, rgba(255, 255, 255, 0.22), transparent 60%);
    border-radius: 3px;
  }
}
.f-corrupt {
  background: linear-gradient(90deg, var(--acc2), var(--acc));
  box-shadow: 0 0 8px var(--glow);
}
.f-user {
  background: linear-gradient(90deg, #b3577e, #e58bab);
}
.f-suwen {
  background: linear-gradient(90deg, #4e5560, #8a93a1);
}
.f-grow {
  background: linear-gradient(90deg, var(--acc2), var(--acc));
  box-shadow: 0 0 6px var(--glow);
}
.bv {
  flex: none;
  min-width: 24px;
  text-align: right;
  font-weight: 700;
  font-size: 12px;
  color: #d5cabb;
  font-variant-numeric: tabular-nums;
}

.vuln-banner {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 7px 11px;
  border-radius: 8px;
  border: 1px solid rgba(255, 107, 157, 0.45);
  background: linear-gradient(90deg, rgba(255, 107, 157, 0.15), rgba(255, 107, 157, 0.03));
  color: $vuln;
  font-size: 12px;
  font-weight: 600;
  letter-spacing: 1px;
  animation: vuln-pulse 1.6s ease-in-out infinite;

  i {
    font-style: normal;
    animation: vuln-sway 0.7s ease-in-out infinite alternate;
  }
}
@keyframes vuln-sway {
  from {
    transform: rotate(-8deg);
  }
  to {
    transform: rotate(8deg);
  }
}

.inner-voice {
  margin: 0;
  padding: 8px 12px;
  border-left: 2px solid color-mix(in srgb, var(--acc) 55%, transparent);
  border-radius: 0 6px 6px 0;
  background: rgba(0, 0, 0, 0.24);
  font-family: $serif;
  font-size: 12.5px;
  font-style: italic;
  color: #cabfaf;
  letter-spacing: 0.3px;
}
.aura {
  font-size: 11px;
  font-style: italic;
  color: color-mix(in srgb, var(--acc) 48%, #887);
  text-align: right;
  letter-spacing: 0.5px;
}

// ━━━ 植入 ━━━
.implant {
  display: flex;
  flex-direction: column;
  gap: 9px;
  padding: 11px 13px;
  border: 1px solid color-mix(in srgb, var(--acc) 30%, transparent);
  border-radius: 10px;
  background: linear-gradient(160deg, color-mix(in srgb, var(--acc) 7%, transparent), transparent 60%);
  backdrop-filter: blur(4px);
}
.implant-head {
  display: flex;
  align-items: center;
  gap: 8px;
}
.ttl {
  font-family: $serif;
  font-size: 13.5px;
  font-weight: 700;
  color: var(--acc);
  letter-spacing: 2px;
  text-shadow: 0 0 8px var(--glow);
}
.target {
  font-size: 11.5px;
  color: color-mix(in srgb, var(--acc) 58%, #998);
  letter-spacing: 0.5px;
}
.quota {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  margin-left: auto;

  .quota-label {
    font-size: 9.5px;
    color: color-mix(in srgb, var(--acc) 45%, #887);
    letter-spacing: 1px;
    margin-right: 2px;
  }
  i {
    width: 7px;
    height: 7px;
    border-radius: 50%;
    background: rgba(255, 255, 255, 0.14);
    transition: background 0.3s;

    &.used {
      background: var(--acc);
      box-shadow: 0 0 6px var(--glow);
    }
  }
}
.implant-row {
  display: flex;
  align-items: center;
  gap: 8px;

  input {
    flex: 1;
    min-width: 0;
    padding: 8px 12px;
    border: 1px solid var(--line);
    border-radius: 8px;
    background: rgba(0, 0, 0, 0.38);
    color: #e6ddcf;
    font-size: 13px;
    font-family: inherit;
    letter-spacing: 0.5px;
    transition: border-color 0.2s, box-shadow 0.2s;

    &:focus {
      outline: none;
      border-color: color-mix(in srgb, var(--acc) 70%, transparent);
      box-shadow: 0 0 10px var(--glow);
    }
    &::placeholder {
      color: color-mix(in srgb, var(--acc) 32%, #666);
    }
  }
}
.count {
  flex: none;
  font-size: 10px;
  color: #766;
  font-variant-numeric: tabular-nums;

  &.max {
    color: $danger;
    font-weight: 700;
  }
}
.go {
  flex: none;
  padding: 8px 18px;
  border: none;
  border-radius: 8px;
  background: linear-gradient(135deg, var(--acc2), var(--acc));
  color: #16100a;
  font-size: 13px;
  font-weight: 800;
  font-family: inherit;
  letter-spacing: 3px;
  cursor: pointer;
  box-shadow: 0 0 12px color-mix(in srgb, var(--acc) 25%, transparent);
  transition: filter 0.2s, transform 0.15s;

  &:hover:not(:disabled) {
    filter: brightness(1.15);
    transform: translateY(-1px);
  }
  &:disabled {
    opacity: 0.3;
    cursor: not-allowed;
  }
}
.msg {
  margin: 0;
  padding: 5px 10px;
  border-radius: 6px;
  font-size: 11.5px;
  letter-spacing: 0.4px;

  &.success {
    color: $safe;
    background: rgba(121, 196, 138, 0.1);
    border-left: 2px solid $safe;
  }
  &.error {
    color: $danger;
    background: rgba(224, 104, 104, 0.1);
    border-left: 2px solid $danger;
  }
  &.warn {
    color: $warn;
    background: rgba(232, 169, 79, 0.1);
    border-left: 2px solid $warn;
  }
}

// ━━━ 卡片 ━━━
.card {
  padding: 11px 13px;
  border: 1px solid var(--line);
  border-radius: 10px;
  background: var(--panel);
  backdrop-filter: blur(3px);
  box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.04);

  h3 {
    display: flex;
    align-items: center;
    gap: 8px;
    margin: 0 0 9px;
    padding-bottom: 7px;
    border-bottom: 1px solid var(--line);
    font-family: $serif;
    font-size: 13px;
    font-weight: 700;
    color: var(--acc);
    letter-spacing: 2px;
    text-shadow: 0 0 8px var(--glow);

    em {
      margin-left: auto;
      font-style: normal;
      font-size: 11px;
      font-weight: 400;
      color: color-mix(in srgb, var(--acc) 48%, #887);
      font-variant-numeric: tabular-nums;
    }
  }
}
.empty {
  margin: 0;
  padding: 8px 0;
  text-align: center;
  font-size: 11.5px;
  font-style: italic;
  color: color-mix(in srgb, var(--acc) 35%, #665);
  letter-spacing: 1px;
}
.note {
  margin: 8px 0 0;
  padding: 5px 9px;
  border-radius: 6px;
  font-size: 11px;

  &.warn {
    color: $warn;
    background: rgba(232, 169, 79, 0.09);
    border-left: 2px solid $warn;
  }
  &.safe {
    color: $safe;
    background: rgba(121, 196, 138, 0.08);
    border-left: 2px solid $safe;
  }
  &.freeze {
    color: $info;
    background: rgba(111, 185, 220, 0.09);
    border-left: 2px solid $info;
  }
  &.pov-running {
    color: var(--acc);
    background: color-mix(in srgb, var(--acc) 8%, transparent);
    border-left: 2px solid var(--acc);
  }
}

// ━━━ 苏文视角按钮（打断后点亮，发光跳动） ━━━
.pov-btn {
  width: 100%;
  margin-top: 2px;
  padding: 7px 10px;
  border-radius: 8px;
  border: 1px solid color-mix(in srgb, var(--acc) 60%, transparent);
  background: linear-gradient(160deg, color-mix(in srgb, var(--acc) 18%, transparent), rgba(0, 0, 0, 0.25));
  color: var(--acc);
  font-size: 12px;
  font-weight: 700;
  font-family: inherit;
  letter-spacing: 2px;
  cursor: pointer;
  animation: pov-throb 1.6s ease-in-out infinite;
  transition: filter 0.2s;

  &:hover {
    filter: brightness(1.15);
  }
}
@keyframes pov-throb {
  0%,
  100% {
    box-shadow: 0 0 5px var(--glow);
    transform: translateY(0);
  }
  50% {
    box-shadow:
      0 0 14px var(--glow),
      0 0 26px var(--glow2);
    transform: translateY(-1px);
  }
}

// ━━━ 苏文卡 ━━━
.chip {
  margin-left: auto;
  font-size: 10.5px;
  font-weight: 600;
  padding: 1px 10px;
  border-radius: 10px;
  letter-spacing: 0.5px;

  &.home {
    color: $danger;
    background: rgba(224, 104, 104, 0.14);
  }
  &.away {
    color: $safe;
    background: rgba(121, 196, 138, 0.14);
  }
  &.sleeping {
    color: $info;
    background: rgba(111, 185, 220, 0.14);
  }
}
.sw-meta {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 8px;
  font-size: 12px;
  color: color-mix(in srgb, var(--acc) 55%, #998);
  margin-bottom: 8px;

  .sw-emo {
    font-size: 11px;
    padding: 1px 10px;
    border-radius: 12px;
    border: 1px solid var(--line);
    background: rgba(0, 0, 0, 0.25);
    color: #cfc6b8;
  }
}
.sw-voice {
  margin-bottom: 9px;
  border-left-color: color-mix(in srgb, var(--acc) 30%, #778);
  color: #b3aa9c;
}
.f-warn {
  background: linear-gradient(90deg, #c98f3d, $warn);
}
.f-danger {
  background: linear-gradient(90deg, #b34848, $danger);
  animation: sus-pulse 1.4s ease-in-out infinite;
}
@keyframes sus-pulse {
  0%,
  100% {
    box-shadow: 0 0 5px rgba(224, 104, 104, 0.5);
  }
  50% {
    box-shadow: 0 0 12px rgba(224, 104, 104, 0.85);
  }
}

// ━━━ 念头条目 ━━━
.thought {
  padding: 8px 10px;
  border-radius: 8px;
  background: rgba(0, 0, 0, 0.26);
  border-left: 2px solid transparent;
  transition: border-color 0.25s, background 0.25s;

  & + .thought {
    margin-top: 7px;
  }
  &:hover {
    background: rgba(0, 0, 0, 0.38);
    border-left-color: var(--acc);
  }
}
.t-head {
  display: flex;
  align-items: center;
  gap: 7px;
  flex-wrap: wrap;
  margin-bottom: 4px;
}
.state {
  font-size: 10px;
  font-weight: 600;
  padding: 1px 8px;
  border-radius: 10px;
  letter-spacing: 0.5px;

  &.growing {
    color: $safe;
    background: rgba(121, 196, 138, 0.14);
  }
  &.pending {
    color: $info;
    background: rgba(111, 185, 220, 0.14);
  }
  &.rejected {
    color: $danger;
    background: rgba(224, 104, 104, 0.14);
  }
  &.mature {
    color: var(--acc);
    background: color-mix(in srgb, var(--acc) 16%, transparent);
  }
  &.expired {
    color: #999;
    background: rgba(255, 255, 255, 0.08);
  }
}
.t-type {
  font-size: 10.5px;
  color: color-mix(in srgb, var(--acc) 50%, #998);
}
.t-diff {
  font-size: 10px;
  color: $warn;
  padding: 0 6px;
  border-radius: 4px;
  border: 1px solid rgba(232, 169, 79, 0.35);
}
.t-discard {
  margin-left: auto;
}
.t-body {
  font-family: $serif;
  font-size: 13px;
  color: #e0d8ca;
  letter-spacing: 0.4px;
  margin-bottom: 4px;
}
.t-prog {
  display: flex;
  align-items: center;
  gap: 8px;

  .track {
    flex: 1;
  }
  .pv {
    flex: none;
    font-size: 10px;
    color: color-mix(in srgb, var(--acc) 52%, #998);
    font-variant-numeric: tabular-nums;
  }
}
.t-reject {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 8px;
  font-size: 11px;
  color: $danger;

  .force {
    border-color: rgba(224, 104, 104, 0.7);
    color: $danger;
    font-weight: 700;
    animation: force-lure 2.2s ease-in-out infinite;

    &:hover {
      background: rgba(224, 104, 104, 0.16);
    }
  }
}
@keyframes force-lure {
  0%,
  100% {
    box-shadow: 0 0 0 rgba(224, 104, 104, 0);
  }
  50% {
    box-shadow: 0 0 9px rgba(224, 104, 104, 0.45);
  }
}

.ghost {
  flex: none;
  padding: 2px 10px;
  border: 1px solid rgba(224, 104, 104, 0.55);
  border-radius: 6px;
  background: transparent;
  color: $danger;
  font-size: 10px;
  font-family: inherit;
  letter-spacing: 0.5px;
  cursor: pointer;
  transition: background 0.2s;

  &:hover {
    background: rgba(224, 104, 104, 0.15);
  }
  &.gold {
    padding: 3px 11px;
    border-color: color-mix(in srgb, var(--acc) 60%, transparent);
    color: var(--acc);

    &:hover {
      background: color-mix(in srgb, var(--acc) 14%, transparent);
    }
  }
}

// ━━━ 习惯 ━━━
.habit {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 8px;
  padding: 6px 10px;
  border-radius: 7px;
  background: rgba(0, 0, 0, 0.26);
  border-left: 2px solid color-mix(in srgb, var(--acc) 40%, transparent);

  & + .habit {
    margin-top: 6px;
  }
}
.h-text {
  font-family: $serif;
  font-size: 12.5px;
  color: #cfe3d0;
}

// ━━━ 仪容星标（满星脉冲） ━━━
.stars {
  display: flex;
  align-items: center;
  gap: 3px;
  margin: -2px 0 6px;
}
.star {
  font-size: 13px;
  line-height: 1;
  color: rgba(255, 255, 255, 0.14);
  transition: color 0.3s, text-shadow 0.3s;

  &.lit {
    color: var(--acc);
    text-shadow: 0 0 6px var(--glow);
  }
}
.stars.full .star {
  animation: star-pulse 1.8s ease-in-out infinite;

  @for $i from 1 through 5 {
    &:nth-child(#{$i}) {
      animation-delay: #{($i - 1) * 0.12}s;
    }
  }
}
@keyframes star-pulse {
  0%,
  100% {
    text-shadow: 0 0 4px var(--glow);
  }
  50% {
    text-shadow:
      0 0 12px var(--glow),
      0 0 22px var(--glow2);
  }
}
.star-note {
  margin-left: 5px;
  font-size: 9.5px;
  letter-spacing: 0.5px;
  color: color-mix(in srgb, var(--acc) 40%, #776);
}
.stars.full .star-note {
  color: var(--acc);
  text-shadow: 0 0 8px var(--glow);
}

// ━━━ 仪容 ━━━
.tags {
  display: flex;
  gap: 6px;
  flex-wrap: wrap;
  margin-bottom: 8px;
}
.tag {
  font-size: 10.5px;
  padding: 2px 10px;
  border-radius: 12px;
  color: var(--acc);
  background: color-mix(in srgb, var(--acc) 13%, transparent);
  letter-spacing: 0.5px;

  &.line {
    background: transparent;
    border: 1px solid color-mix(in srgb, var(--acc) 38%, transparent);
    color: color-mix(in srgb, var(--acc) 72%, #aa9);
  }
  &.eq {
    background: linear-gradient(135deg, color-mix(in srgb, var(--acc) 22%, transparent), color-mix(in srgb, var(--acc) 8%, transparent));
    box-shadow: 0 0 8px color-mix(in srgb, var(--acc) 12%, transparent);
  }
}
.equipped-row {
  display: flex;
  align-items: center;
  gap: 6px;
  flex-wrap: wrap;
  margin-bottom: 8px;

  .eq-label {
    font-size: 10px;
    color: color-mix(in srgb, var(--acc) 45%, #887);
    letter-spacing: 1px;
  }
}
.attire {
  margin: 0;
  display: flex;
  flex-direction: column;

  > div {
    display: flex;
    gap: 10px;
    padding: 3px 0;
    font-size: 11.5px;

    & + div {
      border-top: 1px dashed color-mix(in srgb, var(--acc) 12%, transparent);
    }
  }
  dt {
    flex: none;
    width: 30px;
    color: color-mix(in srgb, var(--acc) 48%, #887);
    letter-spacing: 1px;
    font-size: 10.5px;
    line-height: inherit;
  }
  dd {
    margin: 0;
    color: #cabfaf;
  }
}
