
$safe: #79c48a;
$warn: #e8a94f;
$danger: #e06868;
$serif: 'Noto Serif SC', 'Songti SC', 'STSong', serif;

.shop-panel {
  display: flex;
  flex-direction: column;
  gap: 10px;
}

// ━━━ 页头 ━━━
.shop-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 8px;
  flex-wrap: wrap;
}
.money {
  position: relative;
  display: flex;
  align-items: baseline;
  gap: 5px;

  .coin-gain {
    position: absolute;
    right: -6px;
    top: -10px;
    font-size: 11px;
    color: $safe;
    text-shadow: 0 0 8px rgba(121, 196, 138, 0.6);
    animation: shop-coin-float 1.2s ease-out forwards;
    pointer-events: none;
  }

  .m-icon {
    color: var(--acc);
    text-shadow: 0 0 8px var(--glow);
  }
  .m-val {
    font-size: 18px;
    font-weight: 800;
    color: var(--acc);
    text-shadow: 0 0 12px var(--glow);
    font-variant-numeric: tabular-nums;
  }
  .m-unit {
    font-size: 10.5px;
    color: color-mix(in srgb, var(--acc) 45%, #887);
    letter-spacing: 1px;
  }
}
@keyframes shop-coin-float {
  from {
    opacity: 1;
    transform: translateY(0);
  }
  to {
    opacity: 0;
    transform: translateY(-14px);
  }
}
.target-switch {
  display: flex;
  align-items: center;
  gap: 6px;

  .ts-label {
    font-size: 10.5px;
    color: color-mix(in srgb, var(--acc) 45%, #887);
    letter-spacing: 1px;
    margin-right: 2px;
  }
  .ts-btn {
    padding: 4px 14px;
    border: 1px solid var(--line);
    border-radius: 16px;
    background: rgba(0, 0, 0, 0.28);
    color: #b9ad9a;
    font-size: 12px;
    font-family: inherit;
    letter-spacing: 1px;
    cursor: pointer;
    transition: all 0.25s;

    &.active {
      color: var(--acc);
      font-weight: 700;
      border-color: color-mix(in srgb, var(--acc) 55%, transparent);
      background: color-mix(in srgb, var(--acc) 12%, transparent);
      text-shadow: 0 0 8px var(--glow);
    }
  }
}

// ━━━ 类别 tabs ━━━
.cat-tabs {
  display: flex;
  gap: 6px;
}
.cat-btn {
  flex: 1;
  padding: 7px 6px;
  border: 1px solid var(--line);
  border-radius: 8px;
  background: rgba(0, 0, 0, 0.24);
  color: #b9ad9a;
  font-size: 12px;
  font-family: inherit;
  letter-spacing: 1.5px;
  cursor: pointer;
  transition: all 0.25s;

  &.active {
    color: var(--acc);
    font-weight: 700;
    border-color: color-mix(in srgb, var(--acc) 50%, transparent);
    background: linear-gradient(160deg, color-mix(in srgb, var(--acc) 13%, transparent), transparent);
  }
}

// ━━━ 详情栏 ━━━
.info-bar {
  min-height: 52px;
  padding: 8px 12px;
  border: 1px dashed var(--line);
  border-radius: 9px;
  background: rgba(0, 0, 0, 0.22);
  transition: border-color 0.25s;

  &.active {
    border-style: solid;
    border-color: color-mix(in srgb, var(--acc) 40%, transparent);
    background: color-mix(in srgb, var(--acc) 5%, rgba(0, 0, 0, 0.22));
  }
}
.info-head {
  display: flex;
  align-items: center;
  gap: 7px;
  flex-wrap: wrap;
}
.info-name {
  font-family: $serif;
  font-size: 13.5px;
  font-weight: 700;
  color: var(--acc);
  text-shadow: 0 0 8px var(--glow);
}
.info-tag {
  font-size: 9.5px;
  padding: 0 7px;
  border-radius: 8px;
  color: var(--acc);
  background: color-mix(in srgb, var(--acc) 13%, transparent);

  &.dim {
    color: $warn;
    background: rgba(232, 169, 79, 0.12);
  }
}
.info-price {
  margin-left: auto;
  font-size: 12px;
  font-weight: 700;
  color: var(--acc);
  font-variant-numeric: tabular-nums;
}
.info-desc {
  margin-top: 3px;
  font-size: 11.5px;
  color: #b7ab98;
  letter-spacing: 0.3px;
}
.info-effect {
  margin-top: 2px;
  font-size: 10.5px;
  color: color-mix(in srgb, var(--acc) 60%, #998);
}
.info-placeholder {
  font-size: 11px;
  font-style: italic;
  color: color-mix(in srgb, var(--acc) 32%, #665);
  text-align: center;
  padding: 8px 0;
}

// ━━━ 列表：双列网格 + 固定最小高度（切类目不跳高） ━━━
.item-list {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 6px;
  align-content: start;
  min-height: 210px;
}
@media (min-width: 640px) {
  .item-list {
    grid-template-columns: repeat(3, minmax(0, 1fr));
  }
}
.group-header {
  grid-column: 1 / -1;
  display: flex;
  align-items: center;
  gap: 8px;
  margin-top: 2px;

  &.clickable {
    padding: 6px 8px;
    border: 1px solid var(--line);
    border-radius: 8px;
    background: rgba(0, 0, 0, 0.22);
    cursor: pointer;
    transition: all 0.2s;
    user-select: none;

    &:hover {
      background: rgba(0, 0, 0, 0.34);
    }
    &.open {
      border-color: color-mix(in srgb, var(--acc) 35%, transparent);
      background: color-mix(in srgb, var(--acc) 6%, rgba(0, 0, 0, 0.22));
    }
  }
  .group-arrow {
    font-size: 10px;
    color: color-mix(in srgb, var(--acc) 65%, #998);
    width: 12px;
  }
  .group-label {
    font-size: 10.5px;
    color: color-mix(in srgb, var(--acc) 55%, #998);
    letter-spacing: 2px;
  }
  .group-count {
    font-size: 9.5px;
    color: color-mix(in srgb, var(--acc) 40%, #776);
    font-variant-numeric: tabular-nums;
  }
  .group-line {
    flex: 1;
    height: 1px;
    background: linear-gradient(90deg, var(--line), transparent);
  }
}
.item-card {
  display: flex;
  flex-direction: column;
  gap: 6px;
  padding: 8px 9px;
  border-radius: 8px;
  border: 1px solid transparent;
  border-left: 2px solid transparent;
  background: rgba(0, 0, 0, 0.24);
  cursor: pointer;
  transition: all 0.2s;

  &:hover {
    background: rgba(0, 0, 0, 0.36);
  }
  &.selected {
    border-color: color-mix(in srgb, var(--acc) 35%, transparent);
  }
  &.on {
    border-left-color: var(--acc);
    background: color-mix(in srgb, var(--acc) 7%, rgba(0, 0, 0, 0.24));
  }
}
.card-top {
  display: flex;
  align-items: center;
  gap: 7px;
  min-width: 0;
}
.card-bot {
  display: flex;
  align-items: center;
  gap: 6px;
}
.card-name {
  flex: 1;
  font-size: 12px;
  font-weight: 700;
  color: #e0d8ca;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}
.owners {
  display: inline-flex;
  gap: 3px;
}
.owner {
  font-size: 9px;
  width: 16px;
  height: 16px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  border-radius: 50%;
  color: color-mix(in srgb, var(--acc) 75%, #ba9);
  background: color-mix(in srgb, var(--acc) 12%, transparent);
  border: 1px solid color-mix(in srgb, var(--acc) 30%, transparent);

  &.using {
    color: #16100a;
    background: var(--acc);
    font-weight: 700;
    box-shadow: 0 0 6px var(--glow);
  }
  &.meng.using {
    filter: hue-rotate(20deg);
  }
}
.card-price {
  flex: none;
  font-size: 10.5px;
  color: var(--acc);
  font-variant-numeric: tabular-nums;
}
.card-btn {
  flex: 1;
  min-width: 0;
  padding: 4px 8px;
  border-radius: 7px;
  border: 1px solid color-mix(in srgb, var(--acc) 50%, transparent);
  background: transparent;
  color: var(--acc);
  font-size: 10.5px;
  font-family: inherit;
  letter-spacing: 0.5px;
  cursor: pointer;
  transition: background 0.2s, filter 0.2s;

  &.buy {
    border: none;
    background: linear-gradient(135deg, var(--acc2), var(--acc));
    color: #16100a;
    font-weight: 700;

    &:hover:not(:disabled) {
      filter: brightness(1.12);
    }
  }
  &.equip:hover,
  &.use:hover {
    background: color-mix(in srgb, var(--acc) 14%, transparent);
  }
  &.unequip {
    border-color: rgba(224, 104, 104, 0.5);
    color: $danger;

    &:hover {
      background: rgba(224, 104, 104, 0.12);
    }
  }
  &:disabled {
    opacity: 0.35;
    cursor: not-allowed;
  }
}
// ━━━ 影像档案 ━━━
.tape-list {
  display: flex;
  flex-direction: column;
  gap: 6px;
}
.tape-card {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 8px 10px;
  border-radius: 8px;
  border: 1px solid var(--line);
  background: rgba(0, 0, 0, 0.24);

  .card-btn {
    flex: none;
    width: auto;
  }
}
.tape-main {
  flex: 1;
  min-width: 0;
  display: flex;
  flex-direction: column;
  gap: 2px;
}
.tape-name {
  font-size: 11.5px;
  font-weight: 700;
  color: var(--acc);
}
.tape-desc {
  font-size: 11px;
  color: #b7ab98;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;

  &.pending {
    font-style: italic;
    color: color-mix(in srgb, var(--acc) 35%, #665);
  }
}

.msg {
  margin: 0;
  padding: 5px 10px;
  border-radius: 6px;
  font-size: 11.5px;

  &.success {
    color: $safe;
    background: rgba(121, 196, 138, 0.1);
    border-left: 2px solid $safe;
  }
  &.warn {
    color: $warn;
    background: rgba(232, 169, 79, 0.1);
    border-left: 2px solid $warn;
  }
  &.error {
    color: $danger;
    background: rgba(224, 104, 104, 0.1);
    border-left: 2px solid $danger;
  }
}
